import Balancer from 'react-wrap-balancer'

import { Badge } from '@/components/ui/badge'

export interface Content13Props {
  title: string
  description?: string
  items: string[]
}

export function Content13({
  title,
  description,
  items,
}: Readonly<Content13Props>) {
  return (
    <div className="flex flex-col justify-center">
      <div className="flex w-full flex-col items-center space-y-8">
        <div className="flex flex-col gap-2 text-center">
          {title && (
            <h2 className="text-2xl font-bold">
              <Balancer balance={0.5}>{title}</Balancer>
            </h2>
          )}
          {description && (
            <p className="text-muted-foreground">
              <Balancer balance={0.5}>{description}</Balancer>
            </p>
          )}
        </div>
        {items && items.length > 0 && (
          <ul className="m-0 flex w-full list-none flex-wrap items-center justify-center gap-3 p-0">
            {items.map((item, index) => (
              <li key={`${item}-${index}`}>
                <Badge
                  variant="secondary"
                  className="max-w-full p-3 text-sm wrap-break-word whitespace-normal md:max-w-none md:whitespace-nowrap"
                >
                  {item}
                </Badge>
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  )
}

import { Content13, type Content13Props } from './content-13'

export const values = {
  title: 'Topics',
  description: 'Explore by category or focus area.',
  items: ['Design', 'Code', 'Ship', 'Scale', 'Open source', 'Docs'],
} satisfies Content13Props

export function Content13Example() {
  return (
    <Content13
      title={values.title}
      description={values.description}
      items={values.items}
    />
  )
}
